With.Cte:

					SELECT {{
								Fields
									-Dimension: PointsOfSale
										--Table: PointsOfSaleCte
									-Dimension: Products 
										--Table: ProductsCte
									-Dimension: ProductsSubstitute
										--Table: ProductsSubstituteCte
									-WithComma
	                	   }}
						   {{
								IfRequest
									-Expression: Type
										--MIN(SubstituteReport.Type) AS Type									
									-Expression: Quantity
										--MIN(SubstituteReport.Quantity) AS Quantity
							}}
                    FROM Fact.SubstituteReport
						{{
	                		InnerJoin 
	                			-Dimension: PointsOfSale
	                				--Table: PointsOfSaleCte
								-Table: SubstituteReport
								-On:PointOfSaleId-PointOfSaleId
						}}
		            	{{
		            		InnerJoin 
		            			-Dimension: Products 
		            				--Table: ProductsCte
								-Table: SubstituteReport
								-On: ProductId-ProductId
		            	}}
						{{
	                		InnerJoin 
	                			-Dimension: ProductsSubstitute
	                				--Table: ProductsSubstituteCte
								-Table: SubstituteReport
								-On:ProductSubstituteProductId-RelatedProductId
						}}
						{{
	                		GroupBy
								-Dimension: PointsOfSale
									--Table: PointsOfSaleCte
		            			-Dimension: Products 
		            				--Table: ProductsCte
								-Dimension: ProductsSubstitute
									--Table: ProductsSubstituteCte
		            	}}

With.Query:

					SELECT {{
								Fields
									-Dimension: PointsOfSale
									-Dimension: Products
									-Dimension: ProductsSubstitute
									-WithComma
	                	   }}
						   {{
								IfRequest
									-Expression: Type
										--Type									
									-Expression: Quantity
										--Quantity
									-WhenRequestTotals
										--Default
											---COUNT(*) OVER () AS TotalCount
										--Expression: Type
											---MIN(Type) OVER () AS Type									
										--Expression: Quantity
											---MIN(Quantity) OVER () AS Quantity
							}}
                    FROM GroupedCte
					{{
                		OrderBy
                			-Dimension: PointsOfSale
	            			-Dimension: Products
							-Dimension: ProductsSubstitute
	            	}}
					{{Pagination}}
